#ifndef XANLITE_RGB_WEBUI_H
#define XANLITE_RGB_WEBUI_H
const char* xanlite_rgb_webui = "<!DOCTYPE html>\n<html>\n<head>\n<meta charset=\"UTF-8\">\n<title>Xanlite RGB Remote</title>\n\n<style>\nbody {\nfont-family: Arial, sans-serif;\n}\n\n.container {\ndisplay: grid;\ngrid-template-columns: repeat(4, 100px);\ngap: 10px;\nmax-width: 450px;\n}\n\n.btn {\npadding: 15px;\ntext-align: center;\ncursor: pointer;\nborder-radius: 8px;\nfont-weight: bold;\nuser-select: none;\nborder: 1px solid #444;\n}\n\n.btn:active {\ntransform: scale(0.95);\n}\n</style>\n\n<script>\nfunction sendCommand(cmd) {\nfetch(\"/remote-xanlite-rgb?cmd=\" + cmd)\n.then(response => console.log(\"Sent:\", cmd))\n.catch(error => console.error(error));\n}\n</script>\n\n</head>\n\n<body>\n\n<h2>Xanlite RGB Remote</h2>\n\n<div class=\"container\">\n<div class=\"btn\" onclick=\"sendCommand('BRIGHTER')\">+</div>\n<div class=\"btn\" onclick=\"sendCommand('DIMMER')\">-</div>\n<div class=\"btn\" onclick=\"sendCommand('OFF')\">Off</div>\n<div class=\"btn\" onclick=\"sendCommand('ON')\">On</div>\n\n<div class=\"btn\" onclick=\"sendCommand('RED')\"        style=\"background:#ff0000\">Red</div>\n<div class=\"btn\" onclick=\"sendCommand('GREEN')\"      style=\"background:#00ff00\">Green</div>\n<div class=\"btn\" onclick=\"sendCommand('WHITE')\"      style=\"background:#ffffff\">White</div>\n<div class=\"btn\" onclick=\"sendCommand('BLUE')\"       style=\"background:#0000ff\">Blue</div>\n\n<div class=\"btn\" onclick=\"sendCommand('ORANGE')\"     style=\"background:#FF6300\">Orange</div>\n<div class=\"btn\" onclick=\"sendCommand('TEAL')\"       style=\"background:#006D58\">Teal</div>\n<div class=\"btn\" onclick=\"sendCommand('INDIGO')\"     style=\"background:#5D00FF\">Indigo</div>\n<div class=\"btn\" onclick=\"sendCommand('FLASH')\"      style=\"background:#808080\">Flash</div>\n\n<div class=\"btn\" onclick=\"sendCommand('YELLOW')\"     style=\"background:#FFFF00\">Yellow</div>\n<div class=\"btn\" onclick=\"sendCommand('CYAN')\"       style=\"background:#00DAD4\">Cyan</div>\n<div class=\"btn\" onclick=\"sendCommand('LAVENDER')\"   style=\"background:#B300CA\">Lavender</div>\n<div class=\"btn\" onclick=\"sendCommand('STROBE')\"     style=\"background:#808080\">Strobe</div>\n\n<div class=\"btn\" onclick=\"sendCommand('LIME')\"       style=\"background:#37CC35\">Lime</div>\n<div class=\"btn\" onclick=\"sendCommand('SKYBLUE')\"    style=\"background:#3576CC\">Sky Blue</div>\n<div class=\"btn\" onclick=\"sendCommand('PURPLE')\"     style=\"background:#84004C\">purple</div>\n<div class=\"btn\" onclick=\"sendCommand('FADE')\"       style=\"background:#808080\">Fade</div>\n\n<div class=\"btn\" onclick=\"sendCommand('LIGHTGREEN')\" style=\"background:#0A9800\">Light Green</div>\n<div class=\"btn\" onclick=\"sendCommand('LIGHTBLUE')\"  style=\"background:#0062D1\">Light Blue</div>\n<div class=\"btn\" onclick=\"sendCommand('MAGENTA')\"    style=\"background:#CA0092\">Magenta</div>\n<div class=\"btn\" onclick=\"sendCommand('SMOOTH')\"     style=\"background:#808080\">Smooth</div>\n</div>\n\n</body>\n</html>";
#endif
